addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

// Dangerous headers that should be blocked or normalized
const DANGEROUS_HEADERS = [
  'x-forwarded-host',
  'x-forwarded-scheme',
  'x-original-url',
  'x-rewrite-url',
  'x-host',
  'forwarded',
  'x-forwarded-server'
];

// Headers to include in cache key
const CACHE_KEY_HEADERS = [
  'host',
  'accept-encoding',
  'accept-language'
];

async function handleRequest(request) {
  const url = new URL(request.url);

  // Create sanitized headers
  const sanitizedHeaders = new Headers(request.headers);

  // Remove dangerous headers that could poison cache
  DANGEROUS_HEADERS.forEach(header => {
    sanitizedHeaders.delete(header);
  });

  // Validate and normalize Host header
  const host = sanitizedHeaders.get('host');
  const allowedHosts = ['example.com', 'www.example.com', 'cdn.example.com'];

  if (!allowedHosts.includes(host)) {
    return new Response('Invalid Host header', { status: 400 });
  }

  // Normalize query strings for cache key consistency
  const sortedParams = new URLSearchParams([...url.searchParams].sort());
  url.search = sortedParams.toString();

  // Build custom cache key
  const cacheKeyComponents = [
    url.hostname,
    url.pathname,
    url.search
  ];

  // Add whitelisted headers to cache key
  CACHE_KEY_HEADERS.forEach(header => {
    const value = sanitizedHeaders.get(header);
    if (value) {
      cacheKeyComponents.push(`${header}:${value}`);
    }
  });

  const cacheKey = cacheKeyComponents.join('|');

  // Create modified request
  const modifiedRequest = new Request(url.toString(), {
    method: request.method,
    headers: sanitizedHeaders,
    body: request.body,
    redirect: request.redirect
  });

  // Check cache using custom key
  const cache = caches.default;
  let response = await cache.match(cacheKey);

  if (!response) {
    // Fetch from origin
    response = await fetch(modifiedRequest);

    // Only cache successful GET requests
    if (request.method === 'GET' && response.status === 200) {
      // Add security headers
      const secureResponse = new Response(response.body, response);
      secureResponse.headers.set('Content-Security-Policy', "default-src 'self'");
      secureResponse.headers.set('X-Content-Type-Options', 'nosniff');
      secureResponse.headers.set('X-Frame-Options', 'DENY');
      secureResponse.headers.set('Strict-Transport-Security', 'max-age=31536000');

      // Cache the response
      event.waitUntil(cache.put(cacheKey, secureResponse.clone()));
      return secureResponse;
    }
  }

  return response;
}

