import std;
import var;

# Trusted backend servers
backend default {
    .host = "origin.example.com";
    .port = "443";
    .ssl = true;
}

# List of allowed hostnames
acl allowed_hosts {
    "example.com";
    "www.example.com";
    "cdn.example.com";
}

sub vcl_recv {
    # Remove dangerous headers that could poison cache
    unset req.http.X-Forwarded-Host;
    unset req.http.X-Forwarded-Scheme;
    unset req.http.X-Original-URL;
    unset req.http.X-Rewrite-URL;
    unset req.http.X-Host;
    unset req.http.Forwarded;
    unset req.http.X-Forwarded-Server;
    unset req.http.X-Forwarded-Proto;

    # Validate Host header against whitelist
    if (req.http.host !~ "^(example\.com|www\.example\.com|cdn\.example\.com)$") {
        return (synth(400, "Invalid Host header"));
    }

    # Normalize URL by sorting query parameters
    if (req.url ~ "\?") {
        set req.url = std.querysort(req.url);
    }

    # Only cache GET and HEAD requests
    if (req.method != "GET" && req.method != "HEAD") {
        return (pass);
    }

    # Don't cache authenticated requests
    if (req.http.Authorization || req.http.Cookie ~ "session=") {
        return (pass);
    }

    # Build custom cache key hash
    # Include: hostname, URL, Accept-Encoding
    set req.http.X-Cache-Key = req.http.host + req.url + req.http.Accept-Encoding;

    return (hash);
}

sub vcl_hash {
    # Use custom cache key components
    hash_data(req.http.host);
    hash_data(req.url);

    # Include Accept-Encoding to avoid serving gzip to non-gzip clients
    if (req.http.Accept-Encoding) {
        hash_data(req.http.Accept-Encoding);
    }

    return (lookup);
}

sub vcl_backend_response {
    # Only cache successful responses
    if (beresp.status >= 400) {
        set beresp.uncacheable = true;
        return (deliver);
    }

    # Don't cache responses with Set-Cookie
    if (beresp.http.Set-Cookie) {
        set beresp.uncacheable = true;
        return (deliver);
    }

    # Set cache TTL based on Cache-Control
    if (beresp.http.Cache-Control ~ "max-age") {
        set beresp.ttl = std.duration(regsub(beresp.http.Cache-Control, ".*max-age=(\\d+).*", "\\1s"), 0s);
    } else {
        # Default TTL for cacheable content
        set beresp.ttl = 1h;
    }

    # Add security headers to all cached responses
    set beresp.http.X-Content-Type-Options = "nosniff";
    set beresp.http.X-Frame-Options = "DENY";
    set beresp.http.Strict-Transport-Security = "max-age=31536000; includeSubDomains";

    return (deliver);
}

sub vcl_deliver {
    # Add cache status header for debugging
    if (obj.hits > 0) {
        set resp.http.X-Cache = "HIT";
        set resp.http.X-Cache-Hits = obj.hits;
    } else {
        set resp.http.X-Cache = "MISS";
    }

    # Remove internal headers
    unset resp.http.X-Cache-Key;
    unset resp.http.X-Varnish;
    unset resp.http.Via;

    return (deliver);
}

sub vcl_synth {
    # Custom error page for invalid Host header
    if (resp.status == 400 && resp.reason == "Invalid Host header") {
        set resp.http.Content-Type = "application/json";
        synthetic({"{
            "error": "Invalid Host header",
            "message": "The requested hostname is not allowed",
            "status": 400
        }"});
        return (deliver);
    }
}

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Dangerous headers that indicate potential cache poisoning
const DANGEROUS_HEADERS = [
  'x-forwarded-host',
  'x-forwarded-scheme',
  'x-original-url',
  'x-rewrite-url',
  'x-host',
  'forwarded'
];

// Allowed origin hostnames
const ALLOWED_HOSTS = [
  'example.com',
  'www.example.com',
  'cdn.example.com'
];

// Middleware to block cache poisoning attempts
app.use((req, res, next) => {
  // Check for dangerous headers
  const foundDangerousHeaders = DANGEROUS_HEADERS.filter(header => 
    req.headers[header]
  );

  if (foundDangerousHeaders.length > 0) {
    console.warn('Cache poisoning attempt detected:', {
      ip: req.ip,
      headers: foundDangerousHeaders,
      url: req.url,
      timestamp: new Date().toISOString()
    });

    // Remove dangerous headers
    foundDangerousHeaders.forEach(header => {
      delete req.headers[header];
    });
  }

  // Validate Host header
  const host = req.headers.host?.split(':')[0]; // Remove port
  if (!ALLOWED_HOSTS.includes(host)) {
    return res.status(400).json({
      error: 'Invalid Host header',
      message: 'The requested hostname is not recognized',
      timestamp: new Date().toISOString()
    });
  }

  // Set cache control headers
  if (req.path.startsWith('/api/')) {
    // Never cache API responses
    res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
    res.setHeader('Pragma', 'no-cache');
    res.setHeader('Expires', '0');
  } else if (req.path.match(/\.(js|css|png|jpg|svg)$/)) {
    // Cache static assets with versioning
    res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
  }

  next();
});

// Apply security headers with Helmet
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "https:"],
      connectSrc: ["'self'"],
      fontSrc: ["'self'"],
      objectSrc: ["'none'"],
      mediaSrc: ["'self'"],
      frameSrc: ["'none'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  },
  frameguard: {
    action: 'deny'
  },
  noSniff: true,
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' }
}));

// Rate limiting to prevent cache poisoning attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use('/api/', limiter);

// Example route that could be vulnerable to cache poisoning
app.get('/api/config', (req, res) => {
  // NEVER reflect user-controlled headers in responses
  const config = {
    apiVersion: '1.0',
    environment: process.env.NODE_ENV,
    // DO NOT include: host: req.headers.host (vulnerable to injection)
  };

  res.json(config);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
